import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useSubscription } from '../../contexts/SubscriptionContext';

const PricingPlans = () => {
  const [selectedTier, setSelectedTier] = useState(null);
  const [selectedInterval, setSelectedInterval] = useState('month');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);
  
  const { 
    createCheckoutSession, 
    subscription, 
    loading: subscriptionLoading 
  } = useSubscription();
  
  // Your existing pricing plans and features will remain unchanged
  
  const handleSelectPlan = async (tier, interval) => {
    console.log(`Selecting plan: ${tier} with billing cycle: ${interval}`);
    setSelectedTier(tier);
    setSelectedInterval(interval);
    
    // If selecting the free basic plan
    if (tier === 'basic') {
      // Handle free signup separately
      // This would typically redirect to a different endpoint
      return;
    }
    
    // For paid plans, create checkout session
    try {
      setIsLoading(true);
      setError(null);
      
      console.log('Creating checkout for', tier, 'with billing cycle', interval);
      const response = await createCheckoutSession(tier, interval);
      console.log('Checkout result:', response);
      
      if (!response.success) {
        setError(response.error || 'Failed to create checkout session');
        return;
      }
      
      // If there's a direct URL in the response, use it (recommended approach)
      if (response.url) {
        window.location.href = response.url;
        return;
      }
      
      // Otherwise, if just a session ID is returned
      if (response.sessionId) {
        // If you have Stripe.js initialized:
        if (window.Stripe) {
          const stripe = window.Stripe('pk_test_51R40QxGCjT8uHlI9WQdabIoRw4icN3pWYm7uzGh7BEOiXdbpCIEFrgOBqjrrPHQxJcUwScTYUWwe6dujC9lBoNi300saDYDTse');
          stripe.redirectToCheckout({ sessionId: response.sessionId });
        } else {
          // Fallback direct URL construction if Stripe.js isn't available
          window.location.href = `https://checkout.stripe.com/pay/${response.sessionId}`;
        }
      }
    } catch (error) {
      console.error('Error creating checkout:', error);
      setError('Failed to process your request. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };
  
  // Simple checkout test function
  const handleSimpleCheckout = async () => {
    try {
      console.log('Attempting simple test checkout...');
      setIsLoading(true);
      
      const response = await fetch('http://localhost:31415/api/stripe/simple-checkout', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify({})
      });
      
      const data = await response.json();
      console.log('Simple checkout response:', data);
      
      // Redirect to Stripe Checkout
      if (data.url) {
        window.location.href = data.url;
      } else if (data.sessionId) {
        // Fallback direct URL construction
        window.location.href = `https://checkout.stripe.com/pay/${data.sessionId}`;
      } else {
        setError('Could not create checkout session');
      }
    } catch (error) {
      console.error('Simple checkout error:', error);
      setError('Failed to connect to the server');
    } finally {
      setIsLoading(false);
    }
  };
  
  return (
    <div className="container mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold mb-6 text-center">Subscription Plans</h1>
      
      {/* Test button for debugging */}
      <div className="flex justify-center mb-6">
        <button
          onClick={handleSimpleCheckout}
          disabled={isLoading}
          className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
        >
          {isLoading ? 'Processing...' : 'Test Simple Checkout'}
        </button>
      </div>
      
      {/* Error message */}
      {error && (
        <div className="bg-red-100 text-red-700 p-4 rounded mb-6">
          {error}
        </div>
      )}
      
      {/* Keep your existing rendering logic for pricing plans */}
      {/* This section would contain your current plan cards and UI */}
      
      {/* Make sure each plan card has an onClick handler like this: */}
      {/* 
      <button
        onClick={() => handleSelectPlan(tier, selectedInterval)}
        disabled={isLoading}
        className="your-existing-classes"
      >
        {isLoading ? 'Processing...' : 'Subscribe Now'}
      </button>
      */}
    </div>
  );
};

export default PricingPlans;
